import React from "react";
const SearchBar = ({city,SetCity,onSearch}) => {
    return(
        <div>
            <input
            placeholder="Search for your city"
            value={city}
            onChange={(e)=>setCity(e.target.value)}
            />
            <button onClick={onSearch}>Check Weather</button>
        </div>
    )
}
